record.field:
studio = env['ai.studio'].sudo() field, error = studio.add_custom_field( model_name=model_name, field_name=field_name, field_type=field_type, field_label=field_label, selection=selection, relation=relation, required=required, field_help=field_help, ) if error: ai['result'] = f"ERROR: {error}" else: ai['result'] = ( f"Field created successfully.
" f" Technical name : {field.name}
" f" Label : {field.field_description}
" f" Type : {field.ttype}
" f" Model : {field.model_id.model}
" f"
Next step: call 'AI Studio: Get Views' with model_name='{field.model_id.model}' " f"to find the view ID, then use 'AI Studio: Get View Structure' to determine the correct xpath, " f"then call 'AI Studio: Extend View' to add field '{field.name}' to the form." )

studio = env['ai.studio'].sudo() new_view, error = studio.extend_view( view_id_or_xmlid=view_id_or_xmlid, xpath_expr=xpath_expr, position=position, field_name=field_name, extra_xml=extra_xml, view_key_suffix=view_key_suffix, ) if error: ai['result'] = f"ERROR: {error}" else: ai['result'] = ( f"View extended successfully. Refresh your browser to see the changes.
" f" New view ID : {new_view.id}
" f" Key : {new_view.key}
" f" Extends : {new_view.inherit_id.name} (ID:{new_view.inherit_id.id})
" f" XPath : {xpath_expr}
" f" Position : {position}
" f"
To undo: AI Studio > Custom Views > find ID {new_view.id} > set Active = False" )

studio = env['ai.studio'].sudo() view, act_window, error = studio.create_view( model_name=model_name, view_type=view_type, field_names=field_names, view_name=view_name, create_action=create_action, action_name=action_name, ) if error: ai['result'] = f"ERROR: {error}" else: result = ( f"View created successfully.
" f" View ID : {view.id}
" f" Key : {view.key}
" f" Type : {view.type}
" f" Model : {view.model}
" f" Fields : {', '.join(field_names)}" ) if act_window: result += f"
 Action ID: {act_window.id} (window action created)" ai['result'] = result
